 56→/**
 57→ * This is a temporary class to make the PostListViewModel more manageable. Please feel free to refactor it any way
 58→ * you see fit.
 59→ */
 60→@Suppress("LongParameterList")
 61→class PostActionHandler(
 62→    private val dispatcher: Dispatcher,
 63→    private val site: SiteModel,
 64→    private val postStore: PostStore,
 65→    private val postListDialogHelper: PostListDialogHelper,
 66→    private val doesPostHaveUnhandledConflict: (PostModel) -> Boolean,
 67→    private val hasUnhandledAutoSave: (PostModel) -> Boolean,
 68→    private val triggerPostListAction: (PostListAction) -> Unit,
 69→    private val triggerPostUploadAction: (PostUploadAction) -> Unit,
 70→    private val triggerPublishAction: (PostModel) -> Unit,
 71→    private val invalidateList: () -> Unit,
 72→    private val checkNetworkConnection: () -> Boolean,
 73→    private val showSnackbar: (SnackbarMessageHolder) -> Unit,
 74→    private val showToast: (ToastMessageHolder) -> Unit,
 75→    private val triggerPreviewStateUpdate: (PostListRemotePreviewState, PostInfoType) -> Unit,
 76→    private val copyPost: (SiteModel, PostModel, Boolean) -> Unit
 77→) {
 78→    private val criticalPostActionTracker = CriticalPostActionTracker(onStateChanged = {
 79→        invalidateList.invoke()
 80→    })
 81→
 82→    fun handlePostButton(buttonType: PostListButtonType, post: PostModel, hasAutoSave: Boolean) {
 83→        when (buttonType) {
 84→            BUTTON_EDIT -> editPostButtonAction(site, post)
 85→            BUTTON_RETRY -> triggerPostListAction.invoke(RetryUpload(post))
 86→            BUTTON_MOVE_TO_DRAFT -> {
 87→                moveTrashedPostToDraft(post)
 88→            }
 89→            BUTTON_PUBLISH -> {
 90→                triggerPublishAction.invoke(post)
 91→            }
 92→            BUTTON_SYNC -> {
 93→                postListDialogHelper.showSyncScheduledPostConfirmationDialog(post)
 94→            }
 95→            BUTTON_SUBMIT -> publishPost(post.id)
 96→            BUTTON_VIEW -> triggerPostListAction.invoke(ViewPost(site, post))
 97→            BUTTON_PREVIEW -> triggerPostListAction.invoke(
 98→                PreviewPost(
 99→                    site = site,
100→                    post = post,
101→                    triggerPreviewStateUpdate = triggerPreviewStateUpdate,
102→                    showToast = showToast,
103→                    messageMediaUploading = ToastMessageHolder(
104→                        R.string.editor_toast_uploading_please_wait,
105→                        Duration.SHORT
106→                    )
107→                )
108→            )
109→            BUTTON_STATS -> triggerPostListAction.invoke(ViewStats(site, post))
110→            BUTTON_TRASH -> {
111→                when {
112→                    post.isLocallyChanged -> {
113→                        postListDialogHelper.showTrashPostWithLocalChangesConfirmationDialog(post)
114→                    }
115→                    hasAutoSave -> {
116→                        postListDialogHelper.showTrashPostWithUnsavedChangesConfirmationDialog(post)
117→                    }
118→                    else -> trashPost(post)
119→                }
120→            }
121→            BUTTON_COPY -> copyPost(site, post, true)
122→            BUTTON_COPY_URL -> triggerPostListAction.invoke(copyUrlAction(post))
123→            BUTTON_DELETE, BUTTON_DELETE_PERMANENTLY -> {
124→                postListDialogHelper.showDeletePostConfirmationDialog(post)
125→            }
126→            BUTTON_CANCEL_PENDING_AUTO_UPLOAD -> {
127→                cancelPendingAutoUpload(post)
128→            }
129→            BUTTON_SHOW_MOVE_TRASHED_POST_TO_DRAFT_DIALOG -> {
130→                postListDialogHelper.showMoveTrashedPostToDraftDialog(post)
131→            }
132→            BUTTON_MORE -> {
133→            } // do nothing - ui will show a popup window
134→            BUTTON_PROMOTE_WITH_BLAZE -> {
135→                triggerPostListAction.invoke(PostListAction.ShowPromoteWithBlaze(post))
136→            }
137→            BUTTON_COMMENTS -> {} // todo: implement
138→        }
139→    }
