161→                launch(bgDispatcher) {
162→                    unifiedCommentsListHandler.refreshFromCache(
163→                        ReloadFromCacheParameters(
164→                            pagingParameters = GetPageParameters(
165→                                site = selectedSiteRepository.getSelectedSite()!!,
166→                                number = if (commentFilter == UNREPLIED) {
167→                                    UNREPLIED_COMMENT_PAGE_SIZE
168→                                } else {
169→                                    COMMENT_PAGE_SIZE
170→                                },
171→                                offset = 0,
172→                                commentFilter = commentFilter
173→                            ),
174→                            hasMore = uiState.value.commentData.hasMore
175→                        )
176→                    )
177→                }
178→            }
179→        }
180→    }
