182→    private fun listenToSnackBarRequests() {
183→        launch(bgDispatcher) {
184→            _commentsProvider.filter { it is Failure }.collectLatest {
185→                val errorMessage = if (it.type == BATCH_MODERATE_USE_CASE) {
186→                    UiStringRes(R.string.comment_batch_moderation_error)
187→                } else {
188→                    if ((it as Failure).error.message.isNullOrEmpty()) {
189→                        null
190→                    } else {
191→                        UiStringText(it.error.message)
192→                    }
193→                }
194→
195→                if (errorMessage != null) {
196→                    _onSnackbarMessage.emit(SnackbarMessageHolder(errorMessage))
197→                }
198→            }
199→        }
200→        listenToModerateWithUndoSnackbarRequets()
201→    }
202→
203→    fun listenToModerateWithUndoSnackbarRequets() {
204→        launch(bgDispatcher) {
205→            _commentsProvider.filter { it is Success && it.type == MODERATE_USE_CASE }.collectLatest {
206→                if (it is Success && it.data is SingleCommentModerationResult) {
207→                    val message = when (it.data.newStatus) {
208→                        TRASH -> UiStringRes(R.string.comment_trashed)
209→                        SPAM -> UiStringRes(R.string.comment_spammed)
210→                        else -> UiStringRes(R.string.comment_deleted_permanently)
211→                    }
212→                    commentInModeration.add(it.data.remoteCommentId)
213→                    _onSnackbarMessage.emit(
214→                        SnackbarMessageHolder(
215→                            message = message,
216→                            buttonTitle = UiStringRes(R.string.undo),
217→                            buttonAction = {
218→                                launch(bgDispatcher) {
219→                                    commentInModeration.remove(it.data.remoteCommentId)
220→                                    unifiedCommentsListHandler.undoCommentModeration(
221→                                        ModerateWithFallbackParameters(
222→                                            selectedSiteRepository.getSelectedSite()!!,
223→                                            it.data.remoteCommentId,
224→                                            it.data.newStatus,
225→                                            it.data.oldStatus
226→                                        )
227→                                    )
228→                                }
229→                            },
230→                            onDismissAction = { _ ->
231→                                launch(bgDispatcher) {
232→                                    if (commentInModeration.contains(it.data.remoteCommentId)) {
233→                                        commentInModeration.remove(it.data.remoteCommentId)
234→                                        unifiedCommentsListHandler.moderateAfterUndo(
235→                                            ModerateWithFallbackParameters(
236→                                                selectedSiteRepository.getSelectedSite()!!,
237→                                                it.data.remoteCommentId,
238→                                                it.data.newStatus,
239→                                                it.data.oldStatus
240→                                            )
241→                                        )
242→                                    }
243→                                }
244→                            }
245→                        )
246→                    )
247→                }
248→            }
249→        }
250→    }
