262→    private fun toggleItem(remoteCommentId: Long, commentStatus: CommentStatus) {
263→        viewModelScope.launch {
264→            val selectedComment = SelectedComment(remoteCommentId, commentStatus)
265→            val selectedComments = _selectedComments.value.toMutableList()
266→            if (selectedComments.contains(selectedComment)) {
267→                selectedComments.remove(selectedComment)
268→            } else {
269→                selectedComments.add(selectedComment)
270→            }
271→            _selectedComments.emit(selectedComments)
272→        }
273→    }
