298→    fun performSingleCommentModeration(commentId: Long, newStatus: CommentStatus) {
299→        launch(bgDispatcher) {
300→            if (newStatus == SPAM || newStatus == TRASH || newStatus == DELETED) {
301→                unifiedCommentsListHandler.preModerateWithUndo(
302→                    ModerateCommentParameters(
303→                        selectedSiteRepository.getSelectedSite()!!,
304→                        commentId,
305→                        newStatus
306→                    )
307→                )
308→            } else {
309→                launch(bgDispatcher) {
310→                    unifiedCommentsListHandler.moderateComments(
311→                        ModerateCommentsParameters(
312→                            selectedSiteRepository.getSelectedSite()!!,
313→                            listOf(commentId),
314→                            newStatus
315→                        )
316→                    )
317→                }
318→            }
319→        }
320→    }
321→
322→    fun onBatchModerationConfirmationCanceled() {
323→        launch(bgDispatcher) {
324→            _batchModerationStatus.emit(BatchModerationStatus.Idle)
325→        }
326→    }
327→
328→    fun performBatchModeration(newStatus: CommentStatus) {
329→        launch(bgDispatcher) {
330→            if (!networkUtilsWrapper.isNetworkAvailable()) {
331→                launch(bgDispatcher) {
332→                    _onSnackbarMessage.emit(SnackbarMessageHolder(UiStringRes(R.string.no_network_message)))
333→                }
334→                return@launch
335→            }
336→            if (newStatus == DELETED || newStatus == TRASH) {
337→                _batchModerationStatus.emit(BatchModerationStatus.AskingToModerate(newStatus))
338→            } else {
339→                moderateSelectedComments(newStatus)
340→            }
341→        }
342→    }
343→
344→    private fun moderateSelectedComments(newStatus: CommentStatus) {
345→        launch(bgDispatcher) {
346→            _batchModerationStatus.emit(BatchModerationStatus.Idle)
347→            val commentsToModerate = _selectedComments.value.map { it.remoteCommentId }
348→            _selectedComments.emit(emptyList())
349→            unifiedCommentsListHandler.moderateComments(
350→                ModerateCommentsParameters(
351→                    selectedSiteRepository.getSelectedSite()!!,
352→                    commentsToModerate,
353→                    newStatus
354→                )
355→            )
356→            when (newStatus) {
357→                APPROVED -> analyticsTrackerWrapper.track(COMMENT_BATCH_APPROVED)
358→                UNAPPROVED -> analyticsTrackerWrapper.track(COMMENT_BATCH_UNAPPROVED)
359→                SPAM -> analyticsTrackerWrapper.track(COMMENT_BATCH_SPAMMED)
360→                TRASH -> analyticsTrackerWrapper.track(COMMENT_BATCH_TRASHED)
361→                DELETED -> analyticsTrackerWrapper.track(COMMENT_BATCH_DELETED)
362→                else -> { // noop
363→                }
364→            }
365→        }
366→    }
