 62→class UnifiedCommentListViewModel @Inject constructor(
 63→    private val commentListUiModelHelper: CommentListUiModelHelper,
 64→    private val selectedSiteRepository: SelectedSiteRepository,
 65→    private val networkUtilsWrapper: NetworkUtilsWrapper,
 66→    private val analyticsTrackerWrapper: AnalyticsTrackerWrapper,
 67→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 68→    @Named(UI_THREAD) private val mainDispatcher: CoroutineDispatcher,
 69→    private val unifiedCommentsListHandler: UnifiedCommentsListHandler,
 70→    localCommentCacheUpdateHandler: LocalCommentCacheUpdateHandler
 71→) : ScopedViewModel(mainDispatcher) {
 72→    private var isStarted = false
 73→    private lateinit var commentFilter: CommentFilter
 74→
 75→    private val _commentsUpdateListener = localCommentCacheUpdateHandler.subscribe()
 76→
 77→    private val _onSnackbarMessage = MutableSharedFlow<SnackbarMessageHolder>()
 78→    private val _selectedComments = MutableStateFlow(emptyList<SelectedComment>())
 79→
 80→    private val _batchModerationStatus = MutableStateFlow<BatchModerationStatus>(BatchModerationStatus.Idle)
 81→
 82→    val onSnackbarMessage: SharedFlow<SnackbarMessageHolder> = _onSnackbarMessage
 83→
 84→    private var commentInModeration = ArrayList<Long>()
 85→
 86→    // TODO maybe we can change to some generic Action pattern
 87→    private val _onCommentDetailsRequested = MutableSharedFlow<SelectedComment>()
 88→    val onCommentDetailsRequested: SharedFlow<SelectedComment> = _onCommentDetailsRequested
 89→
 90→    private val _commentsProvider = unifiedCommentsListHandler.subscribe()
 91→
 92→    val uiState: StateFlow<CommentsUiModel> by lazy {
 93→        combine(
 94→            _commentsProvider.filter { it.type == PAGINATE_USE_CASE }.filterIsInstance<CommentsPagingResult>(),
 95→            _selectedComments,
 96→            _batchModerationStatus
 97→        ) { commentData, selectedCommentIds, batchModerationStatus ->
 98→            commentListUiModelHelper.buildUiModel(
 99→                commentFilter,
100→                commentData,
101→                selectedCommentIds,
102→                batchModerationStatus,
103→                uiState.replayCache.firstOrNull(),
104→                this::toggleItem,
105→                this::clickItem,
106→                this::requestNextPage,
107→                this::moderateSelectedComments,
108→                this::onBatchModerationConfirmationCanceled
109→            )
110→        }.stateIn(
111→            scope = viewModelScope,
112→            started = SharingStarted.Companion.WhileSubscribed(UI_STATE_FLOW_TIMEOUT_MS),
113→            initialValue = CommentsUiModel.buildInitialState()
114→        )
115→    }
116→
117→    fun start(commentListFilter: CommentFilter) {
118→        if (isStarted) return
119→        isStarted = true
120→
121→        commentFilter = commentListFilter
122→
123→        listenToLocalCacheUpdateRequests()
124→        listenToSnackBarRequests()
125→        requestsFirstPage()
126→    }
127→
128→    private fun requestsFirstPage() {
129→        launch(bgDispatcher) {
130→            unifiedCommentsListHandler.requestPage(
131→                GetPageParameters(
132→                    site = selectedSiteRepository.getSelectedSite()!!,
133→                    number = if (commentFilter == UNREPLIED) UNREPLIED_COMMENT_PAGE_SIZE else COMMENT_PAGE_SIZE,
134→                    offset = 0,
135→                    commentFilter = commentFilter
136→                )
137→            )
138→        }
139→    }
140→
141→    private fun requestNextPage(offset: Int) {
142→        launch(bgDispatcher) {
143→            unifiedCommentsListHandler.requestPage(
144→                GetPageParameters(
145→                    site = selectedSiteRepository.getSelectedSite()!!,
146→                    number = if (commentFilter == UNREPLIED) {
147→                        UNREPLIED_COMMENT_PAGE_SIZE
148→                    } else {
149→                        COMMENT_PAGE_SIZE
150→                    },
151→                    offset = offset,
152→                    commentFilter = commentFilter
153→                )
154→            )
155→        }
156→    }
157→
158→    private fun listenToLocalCacheUpdateRequests() {
159→        launch(bgDispatcher) {
160→            _commentsUpdateListener.collectLatest {
161→                launch(bgDispatcher) {
162→                    unifiedCommentsListHandler.refreshFromCache(
163→                        ReloadFromCacheParameters(
164→                            pagingParameters = GetPageParameters(
165→                                site = selectedSiteRepository.getSelectedSite()!!,
166→                                number = if (commentFilter == UNREPLIED) {
167→                                    UNREPLIED_COMMENT_PAGE_SIZE
168→                                } else {
169→                                    COMMENT_PAGE_SIZE
170→                                },
171→                                offset = 0,
172→                                commentFilter = commentFilter
173→                            ),
174→                            hasMore = uiState.value.commentData.hasMore
175→                        )
176→                    )
177→                }
178→            }
179→        }
180→    }
181→
182→    private fun listenToSnackBarRequests() {
183→        launch(bgDispatcher) {
184→            _commentsProvider.filter { it is Failure }.collectLatest {
185→                val errorMessage = if (it.type == BATCH_MODERATE_USE_CASE) {
186→                    UiStringRes(R.string.comment_batch_moderation_error)
187→                } else {
188→                    if ((it as Failure).error.message.isNullOrEmpty()) {
189→                        null
190→                    } else {
191→                        UiStringText(it.error.message)
192→                    }
193→                }
194→
195→                if (errorMessage != null) {
196→                    _onSnackbarMessage.emit(SnackbarMessageHolder(errorMessage))
197→                }
198→            }
199→        }
200→        listenToModerateWithUndoSnackbarRequets()
201→    }
202→
203→    fun listenToModerateWithUndoSnackbarRequets() {
204→        launch(bgDispatcher) {
205→            _commentsProvider.filter { it is Success && it.type == MODERATE_USE_CASE }.collectLatest {
206→                if (it is Success && it.data is SingleCommentModerationResult) {
207→                    val message = when (it.data.newStatus) {
208→                        TRASH -> UiStringRes(R.string.comment_trashed)
209→                        SPAM -> UiStringRes(R.string.comment_spammed)
210→                        else -> UiStringRes(R.string.comment_deleted_permanently)
211→                    }
212→                    commentInModeration.add(it.data.remoteCommentId)
213→                    _onSnackbarMessage.emit(
214→                        SnackbarMessageHolder(
215→                            message = message,
216→                            buttonTitle = UiStringRes(R.string.undo),
217→                            buttonAction = {
218→                                launch(bgDispatcher) {
219→                                    commentInModeration.remove(it.data.remoteCommentId)
220→                                    unifiedCommentsListHandler.undoCommentModeration(
221→                                        ModerateWithFallbackParameters(
222→                                            selectedSiteRepository.getSelectedSite()!!,
223→                                            it.data.remoteCommentId,
224→                                            it.data.newStatus,
225→                                            it.data.oldStatus
226→                                        )
227→                                    )
228→                                }
229→                            },
230→                            onDismissAction = { _ ->
231→                                launch(bgDispatcher) {
232→                                    if (commentInModeration.contains(it.data.remoteCommentId)) {
233→                                        commentInModeration.remove(it.data.remoteCommentId)
234→                                        unifiedCommentsListHandler.moderateAfterUndo(
235→                                            ModerateWithFallbackParameters(
236→                                                selectedSiteRepository.getSelectedSite()!!,
237→                                                it.data.remoteCommentId,
238→                                                it.data.newStatus,
239→                                                it.data.oldStatus
240→                                            )
241→                                        )
242→                                    }
243→                                }
244→                            }
245→                        )
246→                    )
247→                }
248→            }
249→        }
250→    }
251→
252→    fun reload() {
253→        if (!networkUtilsWrapper.isNetworkAvailable()) {
254→            launch(bgDispatcher) {
255→                _onSnackbarMessage.emit(SnackbarMessageHolder(UiStringRes(R.string.no_network_message)))
256→            }
257→        } else {
258→            requestsFirstPage()
259→        }
260→    }
261→
262→    private fun toggleItem(remoteCommentId: Long, commentStatus: CommentStatus) {
263→        viewModelScope.launch {
264→            val selectedComment = SelectedComment(remoteCommentId, commentStatus)
265→            val selectedComments = _selectedComments.value.toMutableList()
266→            if (selectedComments.contains(selectedComment)) {
267→                selectedComments.remove(selectedComment)
268→            } else {
269→                selectedComments.add(selectedComment)
270→            }
271→            _selectedComments.emit(selectedComments)
272→        }
273→    }
274→
275→    private fun clickItem(comment: CommentEntity) {
276→        if (_selectedComments.value.isNotEmpty()) {
277→            toggleItem(comment.remoteCommentId, CommentStatus.fromString(comment.status))
278→        } else {
279→            launch {
280→                _onCommentDetailsRequested.emit(
281→                    SelectedComment(
282→                        comment.remoteCommentId,
283→                        CommentStatus.fromString(comment.status)
284→                    )
285→                )
286→            }
287→        }
288→    }
289→
290→    fun clearActionModeSelection() {
291→        viewModelScope.launch {
292→            if (!_selectedComments.value.isNullOrEmpty()) {
293→                _selectedComments.emit(listOf())
294→            }
295→        }
296→    }
297→
298→    fun performSingleCommentModeration(commentId: Long, newStatus: CommentStatus) {
299→        launch(bgDispatcher) {
300→            if (newStatus == SPAM || newStatus == TRASH || newStatus == DELETED) {
301→                unifiedCommentsListHandler.preModerateWithUndo(
302→                    ModerateCommentParameters(
303→                        selectedSiteRepository.getSelectedSite()!!,
304→                        commentId,
305→                        newStatus
306→                    )
307→                )
308→            } else {
309→                launch(bgDispatcher) {
310→                    unifiedCommentsListHandler.moderateComments(
311→                        ModerateCommentsParameters(
312→                            selectedSiteRepository.getSelectedSite()!!,
313→                            listOf(commentId),
314→                            newStatus
315→                        )
316→                    )
317→                }
318→            }
319→        }
320→    }
321→
322→    fun onBatchModerationConfirmationCanceled() {
323→        launch(bgDispatcher) {
324→            _batchModerationStatus.emit(BatchModerationStatus.Idle)
325→        }
326→    }
327→
328→    fun performBatchModeration(newStatus: CommentStatus) {
329→        launch(bgDispatcher) {
330→            if (!networkUtilsWrapper.isNetworkAvailable()) {
331→                launch(bgDispatcher) {
332→                    _onSnackbarMessage.emit(SnackbarMessageHolder(UiStringRes(R.string.no_network_message)))
333→                }
334→                return@launch
335→            }
336→            if (newStatus == DELETED || newStatus == TRASH) {
337→                _batchModerationStatus.emit(BatchModerationStatus.AskingToModerate(newStatus))
338→            } else {
339→                moderateSelectedComments(newStatus)
340→            }
341→        }
342→    }
343→
344→    private fun moderateSelectedComments(newStatus: CommentStatus) {
345→        launch(bgDispatcher) {
346→            _batchModerationStatus.emit(BatchModerationStatus.Idle)
347→            val commentsToModerate = _selectedComments.value.map { it.remoteCommentId }
348→            _selectedComments.emit(emptyList())
349→            unifiedCommentsListHandler.moderateComments(
350→                ModerateCommentsParameters(
351→                    selectedSiteRepository.getSelectedSite()!!,
352→                    commentsToModerate,
353→                    newStatus
354→                )
355→            )
356→            when (newStatus) {
357→                APPROVED -> analyticsTrackerWrapper.track(COMMENT_BATCH_APPROVED)
358→                UNAPPROVED -> analyticsTrackerWrapper.track(COMMENT_BATCH_UNAPPROVED)
359→                SPAM -> analyticsTrackerWrapper.track(COMMENT_BATCH_SPAMMED)
360→                TRASH -> analyticsTrackerWrapper.track(COMMENT_BATCH_TRASHED)
361→                DELETED -> analyticsTrackerWrapper.track(COMMENT_BATCH_DELETED)
362→                else -> { // noop
363→                }
364→            }
365→        }
366→    }
367→
368→    data class SelectedComment(val remoteCommentId: Long, val status: CommentStatus)
369→
370→    companion object {
371→        private const val UI_STATE_FLOW_TIMEOUT_MS = 5000L
372→        private const val COMMENT_PAGE_SIZE = 30
373→        private const val UNREPLIED_COMMENT_PAGE_SIZE = 100
374→    }
375→}
