171→            return;
172→        } else if (!NetworkUtils.isNetworkAvailable(this)) {
173→            ToastUtils.showToast(this, getString(R.string.error_refresh_comments_showing_older));
174→            return;
175→        } else if (!mCanLoadMoreComments) {
176→            AppLog.w(AppLog.T.COMMENTS, "no more comments to be loaded");
177→            return;
178→        }
179→
180→        if (mSite != null && mStatusFilter != null && mAdapter != null) {
181→            mCommentsStoreAdapter.dispatch(CommentActionBuilder.newFetchCommentsAction(
182→                    new FetchCommentsPayload(mSite, mStatusFilter, COMMENTS_PER_PAGE, mAdapter.getCount()))
183→            );
184→            mIsUpdatingComments = true;
