194→            setLoadingState(mBinding, false);
195→            // Don't refresh the list on push, we already updated comments
196→            if (event.causeOfChange != CommentAction.PUSH_COMMENT) {
197→                if (event.changedCommentsLocalIds.size() > 0) {
198→                    loadDataInViewPager(mBinding);
199→                } else if (!event.isError()) {
200→                    // There are no more comments to load
201→                    mCanLoadMoreComments = false;
202→                }
203→            }
204→            if (event.isError()) {
205→                if (!TextUtils.isEmpty(event.error.message)) {
206→                    ToastUtils.showToast(this, event.error.message);
