234→    @SuppressWarnings("deprecation")
235→    private void showCommentList(
236→            @NonNull CommentsDetailActivityBinding binding,
237→            CommentList commentList
238→    ) {
239→        if (isFinishing()) {
240→            return;
241→        }
242→        final int previousItem = binding.viewpager.getCurrentItem();
243→
244→        // Only notify adapter when loading new page
245→        if (mAdapter != null && mAdapter.isAddingNewComments(commentList)) {
246→            mAdapter.onNewItems(commentList);
247→        } else {
248→            if (mSite != null) {
249→                // If current items change, rebuild the adapter
250→                mAdapter = new CommentDetailFragmentAdapter(getSupportFragmentManager(), commentList, mSite,
251→                        CommentsDetailActivity.this);
252→                binding.viewpager.setAdapter(mAdapter);
253→            } else {
254→                throw new IllegalStateException("mAdapter cannot be constructed; mSite is null");
255→            }
256→        }
257→
258→        final int commentIndex = mAdapter.commentIndex(mCommentId);
259→        if (commentIndex < 0) {
260→            showErrorToastAndFinish();
261→        }
262→        if (mOnPageChangeListener != null) {
263→            binding.viewpager.removeOnPageChangeListener(mOnPageChangeListener);
264→        } else {
265→            mOnPageChangeListener = new ViewPager.SimpleOnPageChangeListener() {
266→                @Override
267→                public void onPageSelected(int position) {
268→                    super.onPageSelected(position);
269→                    if (mAdapter != null) {
270→                        final CommentModel comment = mAdapter.getCommentAtPosition(position);
271→                        if (comment != null) {
272→                            mCommentId = comment.getRemoteCommentId();
273→                            // track subsequent comment views
274→                            AnalyticsUtils.trackCommentActionWithSiteDetails(
275→                                    Stat.COMMENT_VIEWED, AnalyticsCommentActionSource.SITE_COMMENTS, mSite);
276→                        }
277→                    }
278→                }
279→            };
280→        }
281→        if (commentIndex != previousItem) {
282→            binding.viewpager.setCurrentItem(commentIndex);
283→        }
284→
285→        binding.viewpager.addOnPageChangeListener(mOnPageChangeListener);
286→    }
